custom_css:
/*
Factorio 1.1
By Min3Mast3r4653
Based off of the Factorio color scheme.
Note: Green buttons confirm and red buttons cancel, this includes the prompts for deleting chats and characters.
*/

* {
--Border: #303031;
--Accent: #FFA200;
--Highlight: #3B3A3B;
--TextInput: #242324;
--Foreground: #313031;
--ActiveTab: F0BF63;
--Tab: #8E8E8E;
--TabActive: #403F40;
--TabHover: #FFAE00;
--Button: #8E8E8E;
--ButtonHover: #E39827;
--ButtonPressed: #272727;
--ButtonConfirm: #5EB663;
--ButtonConfirmHover: #272727;
--ButtonConfirmPressed: #DCD19F;
--ButtonCancelHover: #FE5A5A;
--ButtonC: #272727;
--ButtonCancel: #571F1F;
--Header: #FFE6C0;
--Text: #FFFFFF;
--TextDarkBG: #1D1C1D;
--TextInfo: rgb(117,218,251);
--Black: #1F1922;
--Grey: #858585;
--Red: #C73C08;
--Green: #00B020;
--Blue: #0080B1;
}
#labModeWarning, {
background-color: var(--Red) !important;
color: var(--Header);
}
#reload_chat, #debug_menu, #data_maid_button, #mes_stop, #stscript_stop {
background-color: var(--Button) !important;
color: var(--TextDarkBG);
}
#reload_chat:hover, #debug_menu:hover, #data_maid_button:hover {
background-color: var(--ButtonHover) !important;
}
.popup-controls .popup-button-ok, #stscript_continue {
background-color: var(--ButtonConfirm) !important;
}
.popup-controls .popup-button-ok:hover, #stscript_continue:hover {
background-color: var(--ButtonConfirmHover) !important;
}
.popup-controls .popup-button-cancel, #mes_stop, #stscript_stop {
background-color: var(--ButtonCancel) !important;
}
.popup-controls .popup-button-cancel:hover, #mes_stop:hover, #stscript_stop:hover {
background-color: var(--ButtonCancelHover);
}
textarea, #firstmessage_textarea, #send_textarea, #description_textarea, #persona_description, div#nonQRFormItems, pre, td, #CharListButtonAndHotSwaps, #charListFixedTop, #rm_print_characters_block, .flex-container .justifyCenter, #left-nav-panel, #right-nav-panel, #top-bar, avatar-container interactable, #customCSS, #tagInput {
background-color: var(--TextInput) !important;
}
#user-settings-block, #PersonaManagement, #left-nav-panel:hover, #right-nav-panel:hover, .drawer, #form_sheld, .extraMesButtons, #WorldInfo, #Backgrounds, #rm_extensions_block, #AdvancedFormatting, #rm_api_block, #bulk_tag_popup, #character_popup {
background-color: var(--Foreground);
}
#user-settings-block, #send_form, .extraMesButtons {
padding: 8px;
}
.drawer-icon {
padding: 0;
}
body {
font-family: "Titillium Web", sans-serif;
font-weight: 400;
font-style: normal;
color: var(--Text);
}
h1,h2,h3,h4 {
color: var(--Header) !important;
text-transform: uppercase;
text-align: left;
}
h1,h2 {
font-size: 20px;
}
h3,h4 {
font-size: 18px;
}
#firstmessage_textarea {
min-height: 180px;
}
blockquote {
border-radius: 5px;
border-left: 2px solid var(--Accent) !important;
padding-left: 2px;
margin: 15px;
}
#form_sheld {
margin: 0px;
}
body.big-avatars .avatar, .avatar img {
border: none !important;
margin: 0px;
}
.mes.last_mes {
padding-bottom: 10px;
}
.mes_text p {
line-height: 140%;
font-size: 15px;
}
.extraMesButtons {
margin: 10px;
}
#send_form {
padding-right: 2px;
padding-left: 2px;
border-radius: 0px !important;
padding-bottom: 5px !important;
padding-top: 5px !important;
}
#left-nav-panel, #right-nav-panel {
background-color: #232323;
border: 0px !important;
transition: 0.1s linear;
}
#left-nav-panel:hover, #right-nav-panel:hover {
background-color: var(--Foreground) !important;
transition: 0.05s linear;
}
#chat, #left-nav-panel, #quickReplyBar, #right-nav-panel, #send_form, #top-bar {
border: 0px !important;
margin-top: 0px !important;
}
#right-nav-panel, #top-bar, .drawer-content {
border-radius: 0px;
box-shadow: none !important;
}
hr {
background-image: none;
background-color: #F0BF63;
margin: 10px;
opacity: 1;
height: 2px;
padding: 1px;
}
.mes_block img {
width: 100%; height: auto; margin: 2px;
}
#moonlit-theme-buttons-hint, #textgenerationwebui_api, #kobold_horde, #kobold_api, #novel_api, #bg_chat_hint, #clickSlidersTips, #openai_api, #novel_api {
background-color: var(--Black) !important;
color: var(--TextInfo)
}
